// Menyimpan data rumah sakit ke variabel global (dipakai isochrone & buffer)
let hasilRumahSakitData;

async function loadData(){
    // Mengambil data rumah sakit dari Overpass API
    const rumahSakitResponse = await fetch(url_rumahsakit);
    // Mengonversi respons menjadi format JSON
    const rumahSakitRaw = await rumahSakitResponse.json();

    // Mengonversi format Overpass JSON ke GeoJSON
    const rumahSakitData = {
        type: 'FeatureCollection',
        features: rumahSakitRaw.elements
            .filter(el => el.type === 'node')
            .map(el => ({
                type: 'Feature',
                properties: {
                    NAMA   : el.tags.name || 'Tanpa Nama',
                    ALAMAT : el.tags['addr:full'] || el.tags['addr:street'] || '-',
                    TELEPON: el.tags.phone || el.tags['contact:phone'] || '-',
                    TIPE   : el.tags.amenity === 'hospital' ? 'Rumah Sakit' : 'Klinik'
                },
                geometry: { type: 'Point', coordinates: [el.lon, el.lat] }
            }))
    };

    // Menyimpan data rumah sakit ke variabel global
    hasilRumahSakitData = rumahSakitData;

    // Menampilkan data di konsol untuk verifikasi
    console.log(rumahSakitResponse);
    console.log(rumahSakitData);

    // Menambahkan data rumah sakit ke peta
    map.addSource('rumahsakit', {
        type: 'geojson',
        data: rumahSakitData
    });

    // Menambahkan layer untuk menampilkan rumah sakit
    map.addLayer({
        id: 'rumahsakit-layer',
        source: 'rumahsakit',
        type: 'circle',
        paint: {
            'circle-color': '#ef4444',
            'circle-radius': 5,
            'circle-stroke-width': 1,
            'circle-stroke-color': '#000000'
        },
        layout: {
            'visibility': 'visible'
        }
    });

    // DATA ADMINISTRASI (offline - GeoJSON dari MAPID API)
    const administrasiData = geojsonAdministrasi;

    // Menampilkan data administrasi di konsol untuk verifikasi
    console.log(administrasiData);

    // Menambahkan data administrasi ke peta
    map.addSource('administrasi', {
        type: 'geojson',
        data: administrasiData
    });

    // Menambahkan layer untuk menampilkan administrasi
    map.addLayer({
        id: 'administrasi-layer',
        source: 'administrasi',
        type: 'fill',
        paint: {
            'fill-color': '#27B4F5',
            'fill-opacity': 0.5
        },
        layout: {
            'visibility': 'visible'
        }
    }, 'rumahsakit-layer') // Menambahkan layer administrasi di bawah layer rumah sakit

    // DATA JALAN
    // Mengambil data jalan dari Overpass API
    const jalanResponse = await fetch(url_jalan);
    // Mengonversi respons menjadi format JSON
    const jalanRaw = await jalanResponse.json();

    // Mengonversi format Overpass JSON ke GeoJSON
    const jalanData = {
        type: 'FeatureCollection',
        features: jalanRaw.elements
            .filter(el => el.type === 'way' && el.geometry)
            .map(el => ({
                type: 'Feature',
                properties: {
                    NAMA_JALAN: el.tags.name     || 'Tanpa Nama',
                    TIPE      : el.tags.highway  || '-',
                    REF       : el.tags.ref      || '-',
                    PERMUKAAN : el.tags.surface  || '-',
                    LAJUR     : el.tags.lanes    || '-',
                    MAKS_SPD  : el.tags.maxspeed || '-'
                },
                geometry: {
                    type: 'LineString',
                    coordinates: el.geometry.map(p => [p.lon, p.lat])
                }
            }))
    };

    // Menampilkan data di konsol untuk verifikasi
    console.log(jalanResponse);
    console.log(jalanData);

    // Menambahkan data jalan ke peta
    map.addSource('jalan', {
        type: 'geojson',
        data: jalanData
    });

    // Menambahkan layer untuk menampilkan jalan
    map.addLayer({
        id: 'jalan-layer',
        source: 'jalan',
        type: 'line',
        paint: {
            'line-color': '#F5A227',
            'line-width': 2
        },
        layout: {
            'visibility': 'visible'
        }
    }, 'rumahsakit-layer') // Menambahkan layer jalan di bawah layer rumah sakit

    // TURF JS
    // Menghitung luas kota semarang
    const luas_kota_semarang = turf.area(administrasiData);
    console.log('Luas Kota Semarang', luas_kota_semarang);

    // Mengubah satuan luas dari meter persegi ke kilometer persegi
    const luas_kota_semarang_km = turf.convertArea(luas_kota_semarang, 'meters', 'kilometers');
    console.log('Luas Kota Semarang KM2', luas_kota_semarang_km);

    // Mencari titik centroid kota semarang
    const centroid_kota_semarang = turf.centroid(administrasiData);
    console.log('CENTROID KOTA SEMARANG', centroid_kota_semarang);

    // Menambahkan layer centroid kota semarang
    map.addSource('centroid-kota-semarang', {
        type: 'geojson',
        data: centroid_kota_semarang
    });

    // Menampilkan titik centroid kota semarang
    map.addLayer({
        id: 'centroid-kota-semarang-layer',
        source: 'centroid-kota-semarang',
        type: 'circle',
        paint: {
            'circle-color': '#ffffff',
            'circle-radius': 5,
            'circle-stroke-width': 1,
            'circle-stroke-color': '#000000'
        }
    });

    // Menghitung panjang jalan
    const panjang_jalan = turf.length(jalanData);
    console.log('Panjang Jalan Semarang', panjang_jalan);

    // Membuat buffer awal untuk rumah sakit
    updateBuffer(parseInt(document.getElementById('radius-buffer').value));
}

map.on('load', () => {
    loadData();
})


// Menambahkan event listener untuk menangani klik pada layer rumah sakit
map.on('click', 'rumahsakit-layer', (event) => {

    // Mendapatkan koordinat klik dan properti fitur yang diklik
    const coordinates = event.lngLat;
    const features = event.features[0].properties;

    // Menampilkan informasi fitur yang diklik di konsol untuk verifikasi
    console.log('FEATURES', features);
    console.log('COORDINATES', coordinates);
    console.log('HASIL EVENT CLICK', event);

    // Membuat konten HTML untuk popup berdasarkan properti fitur
    const html = `
        <div>
            <h1> Informasi Rumah Sakit </h1>
            <p> Nama : ${features.NAMA}</p>
            <p> Alamat : ${features.ALAMAT}</p>
            <p> Telepon : ${features.TELEPON}</p>
            <p> Tipe : ${features.TIPE}</p>
        </div>
    `

    new maplibregl.Popup() // Membuat popup baru
    .setHTML(html) // Mengatur konten HTML untuk popup
    .setLngLat(coordinates) // Mengatur posisi popup berdasarkan koordinat klik
    .addTo(map); // Menambahkan popup ke peta
});


// Menambahkan event listener untuk menangani klik pada layer administrasi
map.on('click', 'administrasi-layer', (event) => {

    // Mendapatkan koordinat klik dan properti fitur yang diklik
    const coordinates = event.lngLat;
    const features = event.features[0].properties;

    // Menampilkan informasi fitur yang diklik di konsol untuk verifikasi
    console.log('FEATURES', features);

    // Membuat konten HTML untuk popup berdasarkan properti fitur
    const html = `
        <div>
            <h1> Informasi Administrasi </h1>
            <p> Kabupaten/Kota : ${features['KABUPATEN/KOTA']}</p>
            <p> Provinsi : ${features.PROVINSI}</p>
        </div>
    `

    new maplibregl.Popup() // Membuat popup baru
    .setHTML(html) // Mengatur konten HTML untuk popup
    .setLngLat(coordinates) // Mengatur posisi popup berdasarkan koordinat klik
    .addTo(map); // Menambahkan popup ke peta
});


// Menambahkan event listener untuk menangani klik pada layer jalan
map.on('click', 'jalan-layer', (event) => {

    // Mendapatkan koordinat klik dan properti fitur yang diklik
    const coordinates = event.lngLat;
    const features = event.features[0].properties;

    // Menampilkan informasi fitur yang diklik di konsol untuk verifikasi
    console.log('FEATURES', features);

    // Membuat konten HTML untuk popup berdasarkan properti fitur
    const html = `
        <div>
            <h1> Informasi Jalan </h1>
            <p> Nama Jalan : ${features['NAMA_JALAN']}</p>
            <p> Tipe : ${features['TIPE']}</p>
            <p> Permukaan : ${features['PERMUKAAN']}</p>
        </div>
    `

    new maplibregl.Popup() // Membuat popup baru
    .setHTML(html) // Mengatur konten HTML untuk popup
    .setLngLat(coordinates) // Mengatur posisi popup berdasarkan koordinat klik
    .addTo(map); // Menambahkan popup ke peta
});


