// Fungsi toggle layer rumah sakit
window.toggleLayerRumahSakit = () => {
    const visibility = map.getLayoutProperty('rumahsakit-layer', 'visibility');

    // ketika diklik keadaannya mati, maka layer dibuat nyala, begitu juga sebaliknya
    const nextState = visibility === 'visible' ? 'none' : 'visible'; // Menentukan status berikutnya berdasarkan status saat ini

    console.log('visibility', visibility);
    console.log('nextState', nextState);
    map.setLayoutProperty('rumahsakit-layer', 'visibility', nextState); // Mengubah properti layout untuk layer rumah sakit sesuai dengan status berikutnya
}


