// Fungsi untuk buffer dinamis rumah sakit
window.updateBuffer = (radius) => {
    if (!hasilRumahSakitData) return;
    if (isNaN(radius) || radius <= 0) return;

    // Menghitung buffer dengan Turf.js
    const buffer_rumahsakit = turf.buffer(hasilRumahSakitData, radius, { units: 'meters' });

    // Cek apakah source buffer sudah ada
    if (map.getSource('buffer-rumahsakit')) {
        // Jika sudah ada, update data source saja (tidak perlu hapus layer)
        map.getSource('buffer-rumahsakit').setData(buffer_rumahsakit);
    } else {
        // Menambahkan source buffer rumah sakit
        map.addSource('buffer-rumahsakit', {
            type: 'geojson',
            data: buffer_rumahsakit
        });

        // Menampilkan buffer rumah sakit
        map.addLayer({
            id: 'buffer-rumahsakit-layer',
            source: 'buffer-rumahsakit',
            type: 'fill',
            paint: {
                'fill-color': '#f52727ff',
                'fill-opacity': 0.3
            }
        });
    }
}

// Fungsi untuk menghapus buffer
window.hapusBuffer = () => {
    if (map.getLayer('buffer-rumahsakit-layer')) map.removeLayer('buffer-rumahsakit-layer');
    if (map.getSource('buffer-rumahsakit')) map.removeSource('buffer-rumahsakit');
}


const buttonBuffer = document.getElementById('button-buffer');
buttonBuffer.addEventListener('click', () => {
    const radius = parseInt(document.getElementById('radius-buffer').value);
    updateBuffer(radius);
});

const buttonHapusBuffer = document.getElementById('button-hapus-buffer');
buttonHapusBuffer.addEventListener('click', () => hapusBuffer());

const buttonRun = document.getElementById('button-run');
buttonRun.addEventListener('click', () => execute());


// Fungsi event listener untuk button run isochrone
async function execute(){
    const transportasi = document.getElementById('transportasi').value;
    const waktu = document.getElementById('waktu').value;

    // MENAMPILKAN ISOCHRONE DARI GEOMAPID
    const baseurl = 'https://routing.mapid.io/isochrone';
    const apiKey = '68da7e7d06823ed3f510cc48';
    const point = '-7.005100,110.410300'; // titik koordinat pusat Semarang
    const time = waktu;
    const profile = transportasi;
    const url = `${baseurl}?key=${apiKey}&time_limit=${time}&point=${point}&profile=${profile}`;
    console.log(url);

    // Hit API dengan fetch
    const isochroneResponse = await fetch(url);
    const isochroneData = await isochroneResponse.json();

    console.log('HASIL ISOCHRONE', isochroneData);

    // Mengambil data isochrone dari response API
    const isochoneGeojson = isochroneData.polygons[0];

    // Cek apakah layer isochrone sudah ada, karena maplibre tidak memungkinkan untuk menambahkan layer & source yang sama
    if (map.getSource('isochrone')) {
        // Sebelum hapus source, hapus layer terlebih dahulu baru source nya
        map.removeLayer('isochrone-layer'); // Menghapus layer isochrone
        map.removeSource('isochrone'); // Menghapus source isochrone
    }

    // Menambahkan source isochrone
    map.addSource('isochrone', {
        type: 'geojson',
        data: isochoneGeojson
    });

    // Menampilkan isochrone
    map.addLayer({
        id: 'isochrone-layer',
        source: 'isochrone',
        type: 'fill',
        paint: {
            'fill-color': '#e7f527ff',
            'fill-opacity': 0.5
        }
    });

    // MENAMPILKAN HASIL ANALISIS
    let resultString = '';

    // Looping data rumah sakit
    for (let index = 0; index < hasilRumahSakitData.features.length; index++) {
        // Mengambil data rumah sakit
        const element = hasilRumahSakitData.features[index];

        console.log('DATA RUMAH SAKIT', element);

        // Mengambil koordinat rumah sakit
        const lng = element.geometry.coordinates[0];
        const lat = element.geometry.coordinates[1];

        // Membuat point dan polygon
        const point = turf.point([lng, lat]); // longitude, latitude
        const poly = turf.polygon(isochoneGeojson.geometry.coordinates);

        console.log('APAKAH RUMAH SAKIT BERADA DALAM ISOCHRONE', turf.booleanPointInPolygon(point, poly));

        // Cek apakah rumah sakit berada dalam jangkauan isochrone
        if (turf.booleanPointInPolygon(point, poly)) {

            // Jika iya, menambahkan nama rumah sakit ke list hasil
            // Setiap item bisa diklik untuk zoom ke lokasi (map.flyTo)
            resultString += `<li
                onclick="flyToRumahSakit(${lng}, ${lat}, '${element.properties.NAMA.replace(/'/g, "\\'")}')"
                style="cursor:pointer; padding:6px 8px; margin-bottom:4px; border:1px solid #e2e8f0; border-radius:8px; list-style:none;"
                onmouseover="this.style.background='#eef2ff'"
                onmouseout="this.style.background=''"
            >
                🏥 ${element.properties.NAMA}
            </li>`;
        }

        console.log('HASIL STRING', resultString);

        // Menampilkan hasil analisis pada HTML
        document.getElementById('hasil').innerHTML = resultString || '<li style="list-style:none; color:#94a3b8; font-size:11px; padding:6px;">Tidak ada rumah sakit dalam jangkauan</li>';
    }
}


// Fungsi flyTo ke lokasi rumah sakit yang diklik dari list hasil isochrone
window.flyToRumahSakit = (lng, lat, nama) => {
    console.log('flyTo', nama, lng, lat);

    // Menggunakan map.flyTo untuk zoom ke lokasi rumah sakit yang dipilih
    map.flyTo({
        center: [lng, lat],
        zoom: 15,
        speed: 1.5,
        curve: 1.2,
        essential: true
    });

    // Menampilkan popup setelah flyTo selesai bergerak
    map.once('moveend', () => {
        new maplibregl.Popup()
            .setHTML(`
                <div>
                    <h1> Informasi Rumah Sakit </h1>
                    <p> Nama : ${nama}</p>
                </div>
            `)
            .setLngLat([lng, lat])
            .addTo(map);
    });
}
